import{_ as a,a as r,b as d,c as e}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as l,o as i,c as o,a2 as h}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"マグネットリンクの使い方","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Other/magnet-transfer.md","filePath":"ja-JP/Other/magnet-transfer.md","lastUpdated":1781962217000}'),n={name:"ja-JP/Other/magnet-transfer.md"};function s(p,t,b,c,m,_){return i(),o("div",null,[...t[0]||(t[0]=[h('<h1 id="マグネットリンクの使い方" tabindex="-1">マグネットリンクの使い方 <a class="header-anchor" href="#マグネットリンクの使い方" aria-label="Permalink to &quot;マグネットリンクの使い方&quot;">​</a></h1><p>マグネットリンク機能は、マグネットリンク内のファイルをダウンロードし、指定したクラウド保存先へ自動でアップロードします。</p><p>動画、アニメ、圧縮ファイルなどを ImgBed に転送したいときに使います。リンクを貼り付けるだけで、バックグラウンドでダウンロードタスクが作成され、完了後にアップロード一覧へ最終リンクが表示されます。</p><p><img src="'+a+'" alt="マグネットリンク" loading="lazy"></p><h2 id="使う場所" tabindex="-1">使う場所 <a class="header-anchor" href="#使う場所" aria-label="Permalink to &quot;使う場所&quot;">​</a></h2><p>トップページのアップロードエリアで使います。</p><p>マグネットリンクを入力欄に貼り付け、モードを「転送」にしてアップロードします。</p><p><img src="'+r+'" alt="転送アップロード" loading="lazy"></p><h2 id="事前準備" tabindex="-1">事前準備 <a class="header-anchor" href="#事前準備" aria-label="Permalink to &quot;事前準備&quot;">​</a></h2><p>管理画面でマグネット転送の設定を済ませておきます。</p><p>主に必要なものは次のとおりです。</p><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>GitHub アカウント</td><td>ダウンロードタスクの実行に使います</td></tr><tr><td>アップロード先チャンネル</td><td>Google Drive、OneDrive などの保存先</td></tr><tr><td>保存先ディレクトリ</td><td>転送後のファイルを置く場所</td></tr><tr><td>タイムアウト時間</td><td>長時間タスクの上限</td></tr></tbody></table><h2 id="転送手順" tabindex="-1">転送手順 <a class="header-anchor" href="#転送手順" aria-label="Permalink to &quot;転送手順&quot;">​</a></h2><ol><li>トップページの入力欄にマグネットリンクを貼り付けます。</li><li>モードが「転送」になっていることを確認します。</li><li>アップロードをクリックします。</li><li>タスク作成を待ちます。</li><li>右下の「マグネットタスク」ウィンドウで進行状況を確認します。</li></ol><p>ダウンロード速度は、マグネットの状態、GitHub の実行環境、保存先チャンネルの状況に左右されます。</p><p><img src="'+d+'" alt="ダウンロード中" loading="lazy"></p><h2 id="完了後" tabindex="-1">完了後 <a class="header-anchor" href="#完了後" aria-label="Permalink to &quot;完了後&quot;">​</a></h2><p>タスクが完了すると、アップロード一覧にファイル名とリンクが表示されます。</p><p>動画は動画プレビュー、画像は画像プレビュー、その他のファイルは通常のファイルアイコンで表示されます。</p><p><img src="'+e+'" alt="完了した動画" loading="lazy"></p><p>コピーできる形式は次のとおりです。</p><table tabindex="0"><thead><tr><th>リンク形式</th><th>使いどころ</th></tr></thead><tbody><tr><td>元リンク</td><td>ファイルを直接開く</td></tr><tr><td>Markdown</td><td>Markdown 記事や説明文に貼る</td></tr><tr><td>HTML</td><td>Web ページのコードに貼る</td></tr><tr><td>BBCode</td><td>BBCode 対応フォーラムに貼る</td></tr></tbody></table><h2 id="よくある確認ポイント" tabindex="-1">よくある確認ポイント <a class="header-anchor" href="#よくある確認ポイント" aria-label="Permalink to &quot;よくある確認ポイント&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状態</th><th>意味</th></tr></thead><tbody><tr><td>待機中</td><td>タスクは作成済みで、実行待ちです</td></tr><tr><td>ダウンロード中</td><td>マグネットの内容を取得しています</td></tr><tr><td>アップロード中</td><td>取得したファイルを保存先へアップロードしています</td></tr><tr><td>完了</td><td>ファイルがアップロードされ、リンクをコピーできます</td></tr><tr><td>失敗</td><td>エラー内容を確認して再実行してください</td></tr></tbody></table><h2 id="トラブル時" tabindex="-1">トラブル時 <a class="header-anchor" href="#トラブル時" aria-label="Permalink to &quot;トラブル時&quot;">​</a></h2><ul><li>リンク貼り付け後に始まらない場合は、マグネット転送が有効で、GitHub アカウントと保存先チャンネルが選択されているか確認します。</li><li>速度が極端に遅い場合は、マグネット側に有効なピアが少ない可能性があります。</li><li>完了後にプレビューが出ない場合は、まずファイルリンクを直接開けるか確認します。</li><li>失敗する場合は、マグネットリンク、保存先チャンネル、アップロード先ディレクトリを見直します。</li></ul>',26)])])}const q=l(n,[["render",s]]);export{g as __pageData,q as default};
